RtHook(final Request req, final Repo repo, final int number) {
    final Coordinates coords = repo.coordinates();
    this.request = req.uri()
        .path("/repos")
        .path(coords.user())
        .path(coords.repo())
        .path("/hooks")
        .path(Integer.toString(number))
        .back();
    this.owner = repo;
    this.num = number;
}
